import React, { useState } from 'react';
import { TAGS } from '../data';

export default function PostServiceModal({ onClose, onSubmit }) {
  const [form, setForm]       = useState({ title: '', bio: '', zip: '', rate: '' });
  const [selectedTags, setTags] = useState([]);

  const u = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const toggleTag = t => setTags(tt => tt.includes(t) ? tt.filter(x => x !== t) : [...tt, t]);

  const handleSubmit = () => {
    if (!form.title || selectedTags.length === 0 || !form.zip) {
      alert('Please fill in a headline, at least one skill, and your zip code.');
      return;
    }
    onSubmit({ ...form, skills: selectedTags });
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <h2 style={{ fontSize: 20, color: 'var(--navy)' }}>Post Your Services</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: 22, cursor: 'pointer', color: '#94a3b8' }}>✕</button>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <div>
            <label>Headline *</label>
            <input
              type="text"
              placeholder="e.g. Reliable Handyman & Home Repair"
              value={form.title}
              onChange={e => u('title', e.target.value)}
              autoFocus
            />
          </div>

          <div>
            <label>Service Categories * (pick all that apply)</label>
            <div className="tag-cloud">
              {TAGS.map(t => (
                <span key={t} className={`tag ${selectedTags.includes(t) ? 'active' : ''}`} onClick={() => toggleTag(t)}>
                  {t}
                </span>
              ))}
            </div>
            {selectedTags.length > 0 && (
              <div style={{ fontSize: 12, color: 'var(--green-dark)', marginTop: 4 }}>
                ✓ {selectedTags.length} selected: {selectedTags.join(', ')}
              </div>
            )}
          </div>

          <div>
            <label>About You / Bio</label>
            <textarea
              rows={4} style={{ resize: 'none' }}
              placeholder="Describe your experience, what you offer, and why customers should pick you..."
              value={form.bio}
              onChange={e => u('bio', e.target.value)}
            />
          </div>

          <div className="grid-2">
            <div>
              <label>Zip Code *</label>
              <input type="text" value={form.zip} onChange={e => u('zip', e.target.value)} maxLength={5} placeholder="Service area" />
            </div>
            <div>
              <label>Hourly Rate ($)</label>
              <input type="text" value={form.rate} onChange={e => u('rate', e.target.value)} placeholder="e.g. 45" />
            </div>
          </div>

          <button className="btn-primary" style={{ width: '100%', justifyContent: 'center' }} onClick={handleSubmit}>
            Publish My Profile →
          </button>
        </div>
      </div>
    </div>
  );
}
